import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

const API_ENDPOINTS = [
  {
    name: 'Save RFID Transaction Details',
    endpoint: 'SaveRFIDTransactionDetails',
    method: 'POST',
    authRequired: false,
    sampleBody: [
      {
        "client_code": "SONI123",
        "RFIDNumber": "RFID001",
        "Itemcode": "ITEM001",
        "category_id": "Gold",
        "product_id": "Necklace",
        "design_id": "Fancy Design",
        "purity_id": "22KT",
        "grosswt": "15.000",
        "stonewt": "0.500",
        "diamondWeight": "0.200",
        "netwt": "14.300",
        "box_details": "Box 1",
        "size": "Medium",
        "stoneamount": "200",
        "diamondAmount": "500",
        "HallmarkAmount": "150",
        "MakingPerGram": "30",
        "MakingFixedAmt": "50",
        "MakingPercentage": "10",
        "MRP": "20000",
        "imageurl": "https://example.com/image.jpg",
        "status": "ApiActive"
      }
    ]
  },
  {
    name: 'Update RFID Transaction Details',
    endpoint: 'UpdateRFIDTransactionDetails',
    method: 'POST',
    authRequired: false,
    sampleBody: [
      {
        "client_code": "SONI123",
        "RFIDNumber": "RFID001",
        "status": "Sold"
      }
    ]
  },
  {
    name: 'Get RFID Transaction Details',
    endpoint: 'GetRFIDTransactionDetails',
    method: 'POST',
    authRequired: false,
    sampleBody: {
      "client_code": "SONI123",
      "status": "ApiActive"
    }
  },
  {
    name: 'Delete Labelled Stock Items',
    endpoint: 'DeleteLabelledStockItems',
    method: 'POST',
    authRequired: true,
    permissionRequired: 'delete_stock_items',
    sampleBody: {
      "ClientCode": "SONI123",
      "ItemCodes": ["ITEM001", "ITEM002", "ITEM003"]
    }
  }
];

const Dashboard = () => {
  const [selectedApi, setSelectedApi] = useState(null);
  const [requestBody, setRequestBody] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
      return;
    }
  }, [navigate]);

  const handleApiSelect = (api) => {
    setSelectedApi(api);
    setRequestBody(JSON.stringify(api.sampleBody, null, 2));
    setResponse('');
    setError('');
  };

  const handleSendRequest = async () => {
    if (!selectedApi) return;

    setLoading(true);
    setError('');
    setResponse('');

    try {
      const config = {
        headers: {
          'Content-Type': 'application/json'
        }
      };

      // Add authorization header if required
      if (selectedApi.authRequired) {
        const token = localStorage.getItem('token');
        if (!token) {
          throw new Error('Authentication required. Please login again.');
        }
        config.headers['Authorization'] = `Bearer ${token}`;
      }

      const url = `https://soni.loyalstring.co.in/api/${selectedApi.endpoint}`;
      let result;

      if (selectedApi.method === 'POST') {
        result = await axios.post(url, JSON.parse(requestBody), config);
      }

      setResponse(JSON.stringify(result.data, null, 2));
      toast.success('API request successful!');
    } catch (err) {
      const errorMessage = err.response?.data?.message || err.message || 'An error occurred while making the request.';
      setError(errorMessage);
      toast.error(errorMessage);
      
      if (err.response?.status === 401) {
        localStorage.removeItem('token');
        navigate('/login');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    toast.success('Logged out successfully!');
    navigate('/login');
  };

  return (
    <div className="container-fluid mt-4">
      <ToastContainer />
      <div className="row">
        <div className="col-md-3">
          <div className="card">
            <div className="card-header d-flex justify-content-between align-items-center">
              <h5 className="mb-0">RFID Transaction APIs</h5>
              <button className="btn btn-sm btn-danger" onClick={handleLogout}>
                Logout
              </button>
            </div>
            <div className="list-group list-group-flush">
              {API_ENDPOINTS.map((api, index) => (
                <button
                  key={index}
                  className={`list-group-item list-group-item-action ${
                    selectedApi?.endpoint === api.endpoint ? 'active' : ''
                  }`}
                  onClick={() => handleApiSelect(api)}
                >
                  <div>
                    {api.name}
                    {api.authRequired && (
                      <span className="badge bg-warning ms-2">Auth Required</span>
                    )}
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
        <div className="col-md-9">
          {selectedApi ? (
            <div className="card">
              <div className="card-header">
                <h5 className="mb-0">{selectedApi.name}</h5>
                <small className="text-muted">
                  {selectedApi.method} /api/{selectedApi.endpoint}
                  {selectedApi.authRequired && (
                    <span className="badge bg-warning ms-2">Authentication Required</span>
                  )}
                </small>
              </div>
              <div className="card-body">
                <div className="mb-3">
                  <label className="form-label">Request Body</label>
                  <textarea
                    className="form-control"
                    rows="10"
                    value={requestBody}
                    onChange={(e) => setRequestBody(e.target.value)}
                  />
                </div>
                <button
                  className="btn btn-primary"
                  onClick={handleSendRequest}
                  disabled={loading}
                >
                  {loading ? 'Sending...' : 'Send Request'}
                </button>
                {error && (
                  <div className="alert alert-danger mt-3">{error}</div>
                )}
                {response && (
                  <div className="mt-3">
                    <label className="form-label">Response</label>
                    <pre className="bg-light p-3 rounded">
                      <code>{response}</code>
                    </pre>
                  </div>
                )}
              </div>
            </div>
          ) : (
            <div className="text-center mt-5">
              <h4>Select an API endpoint to get started</h4>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
